 1→/* eslint-disable @typescript-eslint/no-var-requires */
 2→const { createProxyMiddleware } = require('http-proxy-middleware');
 3→const { env } = require('process');
 4→
 5→/* eslint-disable-next-line no-nested-ternary */
 6→const target = env.ASPNETCORE_HTTPS_PORT ? `https://localhost:${env.ASPNETCORE_HTTPS_PORT}`
 7→  : env.ASPNETCORE_URLS ? env.ASPNETCORE_URLS.split(';')[0] : 'http://localhost:9320';
 8→
 9→const context = [
10→  '/weatherforecast',
11→];
12→
13→const onError = (err) => {
14→  console.error(`${err.message}`);
15→};
16→
17→module.exports = function (app) {
18→  const appProxy = createProxyMiddleware(context, {
19→    proxyTimeout: 10000,
20→    target,
21→    // Handle errors to prevent the proxy middleware from crashing when
22→    // the ASP NET Core webserver is unavailable
23→    onError,
24→    secure: false,
25→    // Uncomment this line to add support for proxying websockets
26→    // ws: true,
27→    headers: {
28→      Connection: 'Keep-Alive',
29→    },
30→  });
31→
32→  app.use(appProxy);
33→};
