 24→    /// <summary>
 25→    /// Provides extension methods for configuring the OnePortal application.
 26→    /// </summary>
 27→    public static class OnePortalApplicationBuilderExtension
 28→    {
 29→        /// <summary>
 30→        /// Configures the application to use OnePortal services and middleware.
 31→        /// It follow the latest template for ASP.NET Core 8.0 and later. Need to use with AddOnePortalFalconServicesSPA.
 32→        /// </summary>
 33→        /// <param name="app">The application builder.</param>
 34→        /// <param name="oneportalConfig">oneportalConfig.</param>
 35→        /// <exception cref="ArgumentNullException">Thrown when <paramref name="app"/> is null.</exception>
 36→        public static void UseOnePortalSPA(this IApplicationBuilder app, OnePortalConfig oneportalConfig)
 37→        {
 38→            if (app == null)
 39→            {
 40→                throw new ArgumentNullException(nameof(app));
 41→            }
 42→
 43→            var envProps = app.ApplicationServices.GetService<IEnvironmentProperties>();
 44→
 45→            app.UseDefaultFiles();
 46→            app.UseStaticFiles();
 47→
 48→            app.UseMiddleware<OnePortalMiddleware>();
 49→            app.UseWebSockets();
 50→
 51→            app.UseRouting();
 52→
 53→            if (envProps!.Environment != EnvironmentEnum.ProductionEnvironment)
 54→            {
 55→                app.UseDeveloperExceptionPage();
 56→            }
 57→
 58→            var cookiePolicyOptions = new CookiePolicyOptions
